def _require_env(name: str) -> str:
    """Load an env var and stop with a clear message if it is missing."""
    val = os.getenv(name)
    if not val:
        st.error(
            f"**Missing required configuration:** `{name}` is not set. "
            "Please add it to your `.env` file and restart the app."
        )
        st.stop()
    os.environ[name] = val
    return val

