# HIGH FIX #7: URL validation — prevent SSRF and restrict to supported domains.
# ─────────────────────────────────────────────────────────────────────────────
_PRIVATE_NETS = [
    ipaddress.ip_network("10.0.0.0/8"),
    ipaddress.ip_network("172.16.0.0/12"),
    ipaddress.ip_network("192.168.0.0/16"),
    ipaddress.ip_network("127.0.0.0/8"),
    ipaddress.ip_network("169.254.0.0/16"),  # GCP metadata endpoint lives here
    ipaddress.ip_network("::1/128"),
    ipaddress.ip_network("fc00::/7"),
]
_ALLOWED_YT_DOMAINS = {
    "youtube.com", "www.youtube.com", "youtu.be", "m.youtube.com",
}


def validate_url(url: str) -> tuple[bool, str]:
    """Return (is_valid, error_message). Empty error_message means valid."""
    if not url or not url.strip():
        return False, "URL cannot be empty."

    try:
        parsed = urlparse(url.strip())
    except Exception:
        return False, "Malformed URL."

    if parsed.scheme not in ("http", "https"):
        return False, "Only http:// and https:// URLs are supported."

    host = (parsed.hostname or "").lower()
    if not host:
        return False, "URL has no hostname."

    # Block private/loopback/link-local IPs (SSRF protection)
    try:
        ip = ipaddress.ip_address(host)
        for net in _PRIVATE_NETS:
            if ip in net:
                return False, "Private or internal IP addresses are not allowed."
    except ValueError:
        pass  # Not a raw IP — hostname, proceed

    is_m3u8 = url.endswith(".m3u8") or "m3u8" in parsed.path.lower()
    is_youtube = host in _ALLOWED_YT_DOMAINS

    if not is_youtube and not is_m3u8:
        return (
            False,
            f"Unsupported source '{host}'. Provide a YouTube URL "
            "or a direct .m3u8 HLS stream URL.",
        )

    return True, ""


