    if model_choice == "turbo":
        return whisper.load_model("turbo")
    elif model_choice == "large":
        return whisper.load_model("large-v3")
    else:
        return whisper.load_model("medium")


# ─────────────────────────────────────────────────────────────────────────────
# Helpers
# ─────────────────────────────────────────────────────────────────────────────
def format_timestamp(seconds: float) -> str:
    millis = int((seconds % 1) * 1000)
    mins   = int(seconds // 60)
    secs   = int(seconds % 60)
    return f"{mins:02}:{secs:02}.{millis:03}"


def compute_confidence(segment: dict) -> float:
    lp = segment.get("avg_logprob", -5.0)
    lp_score = max(min((lp - (-6.0)) / (0.0 - (-6.0)), 1.0), 0.0)
    speech_factor = 1.0 - segment.get("no_speech_prob", 0.0)
    return float(max(0.0, min(1.0, 0.8 * lp_score + 0.2 * speech_factor)))


def compute_overall_confidence(result: dict) -> float:
    segments = result.get("segments", [])
    if not segments:
        return 0.0
    total_dur  = sum(max(0.001, s["end"] - s["start"]) for s in segments)
    weighted   = sum(compute_confidence(s) * max(0.001, s["end"] - s["start"]) for s in segments)
    return float(weighted / total_dur)


def label_confidence(score: float) -> str:
    if score >= 0.70:
        return "High ✅"
    elif score >= 0.40:
        return "Medium ⚠️"
    return "Low ❌"


# ─────────────────────────────────────────────────────────────────────────────
# MEDIUM FIX: split_text — sentence-boundary splitting instead of raw char slice.
# The original `text[i:i+4000]` could cut mid-word and produce garbled
# translations at chunk boundaries.
# ─────────────────────────────────────────────────────────────────────────────
def split_text(text: str, max_length: int = 4000) -> list[str]:
    """
    Split text on sentence endings (. ! ?) and group into chunks of at most
    max_length characters, never cutting mid-sentence.
    """
    sentences = re.split(r"(?<=[.!?])\s+", text.strip())
    chunks: list[str] = []
    current = ""

    for sentence in sentences:
        if len(current) + len(sentence) + 1 > max_length:
            if current:
                chunks.append(current.strip())
            # Hard-split sentences that exceed max_length on their own
            while len(sentence) > max_length:
                chunks.append(sentence[:max_length])
                sentence = sentence[max_length:]
            current = sentence
        else:
            current = (current + " " + sentence).strip() if current else sentence

    if current:
        chunks.append(current.strip())

    return chunks


# ─────────────────────────────────────────────────────────────────────────────
# LOW FIX: compute_translation_confidence moved to module level.
# It was previously defined inside the loop of translate_to_english(), causing
# Python to recreate the function object on every iteration.
# NOTE: This calls Google Translate API twice per chunk (round-trip).
# Only invoke it when you intend to display the score.
# ─────────────────────────────────────────────────────────────────────────────
def compute_translation_confidence(
    original_text: str, translated_text: str, source_lang: str = "auto"
) -> float:
    """Estimate translation quality via round-trip similarity (0.0–1.0)."""
    try:
        back = GoogleTranslator(source="en", target=source_lang).translate(translated_text)
        return float(max(0.0, min(1.0, SequenceMatcher(None, original_text, back).ratio())))
    except Exception:
        return 0.0


def download_m3u8_audio(m3u8_url: str) -> str | None:
    output_path = get_output_path()
    result = subprocess.run(
        ["ffmpeg", "-y", "-i", m3u8_url,
         "-vn", "-ar", "16000", "-ac", "1",
         "-c:a", "pcm_s16le",
         "-af", "highpass=f=200, lowpass=f=3000, dynaudnorm",
         output_path],
        stdout=subprocess.PIPE,
        stderr=subprocess.PIPE,
    )
    return output_path if result.returncode == 0 else None


def find_all_word_timestamps(result: dict, target_word: str) -> list[float]:
    timestamps = []
    for seg in result["segments"]:
        for w in seg.get("words", []):
            if target_word.lower() in w["word"].lower():
                timestamps.append(w["start"])
    return timestamps


def generate_video_clip(
    start_time: float, m3u8_url: str, clip_file: str, duration: int = 15, offset: int = 5
) -> str:
    adjusted_start = max(0, start_time - offset)
    subprocess.run(
        ["ffmpeg", "-y", "-ss", str(adjusted_start), "-i", m3u8_url,
         "-t", str(duration), "-c", "copy", clip_file],
        stdout=subprocess.PIPE, stderr=subprocess.PIPE,
    )
    return clip_file


def split_audio(file_path: str, chunk_length: int = 60) -> list[str]:
    audio = AudioSegment.from_file(file_path)
    chunks = []
    for i in range(0, len(audio), chunk_length * 1000):
        chunk = audio[i:i + chunk_length * 1000]
        tmp = tempfile.NamedTemporaryFile(delete=False, suffix=".wav")
        chunk.export(tmp.name, format="wav")
        chunks.append(tmp.name)
    return chunks


def merge_results(results: list[dict]) -> dict:
    merged: dict = {"text": "", "segments": [], "language": None}
    for r in results:
        merged["text"] += r["text"] + " "
        merged["segments"].extend(r["segments"])
        if merged["language"] is None:
            merged["language"] = r.get("language")
    return merged


def validate_audio(file_path: str) -> None:
    if not os.path.exists(file_path):
        raise FileNotFoundError(f"File not found: {file_path}")
    if os.path.getsize(file_path) == 0:
        raise ValueError("Audio file is empty (0 bytes).")
    try:
        f = sf.SoundFile(file_path)
        if len(f) == 0:
            raise ValueError("Audio file has no frames.")
    except Exception as e:
        raise ValueError(f"Invalid audio file: {e}")


def read_transcript(file_path: str, results: dict) -> str:
    with open(file_path, "w", encoding="utf-8") as fh:
        for seg in results["segments"]:
            conf = compute_confidence(seg)
            fh.write(
                f"[{format_timestamp(seg['start'])} --> {format_timestamp(seg['end'])}]"
                f"  {seg['text'].strip()}  (Conf: {conf:.2f})\n"
            )
    with open(file_path, "r", encoding="utf-8") as fh:
        return fh.read()


def translate_to_english(file_path: str, results: dict, source_lang: str = "auto") -> None:
    """Translate the transcript to English and store it in session state."""
    text = read_transcript(file_path, results)
    text_chunks = split_text(text)

    with st.status("Translating to English", expanded=True) as status:
        try:
            translator = GoogleTranslator(source=source_lang, target="en")
            translated_chunks = [translator.translate(chunk) for chunk in text_chunks]
            st.session_state.english_translated_text = " ".join(translated_chunks)
            st.text_area(
                "English Translation",
                st.session_state.english_translated_text,
                height=500,
            )
            # LOW FIX: confidence_scores were computed but never displayed — removed
            # the dead code and the wasted double-API-call it caused.
            status.update(label="Translated to English", state="complete")
        except Exception as e:
            st.error(f"Translation failed: {e}")


def safe_transcribe(model, audio_path: str, **kwargs) -> dict:
    if not os.path.exists(audio_path):
        raise FileNotFoundError(f"Audio file not found: {audio_path}")
    if os.path.getsize(audio_path) == 0:
        raise ValueError(f"Audio file {audio_path} is empty.")
    try:
        info = sf.info(audio_path)
        if info.frames / info.samplerate <= 0:
            raise ValueError(f"Audio file {audio_path} has zero duration.")
    except RuntimeError:
        raise ValueError(f"Cannot read audio metadata: {audio_path}")

    try:
        result = model.transcribe(audio_path, **kwargs)
    except RuntimeError as e:
        if "cannot reshape tensor of 0 elements" in str(e):
            raise ValueError("Whisper received empty audio features. Check the input file.")
        raise

    if not result.get("text") or result["text"].strip() == "":
        result["text"] = "[No speech detected]"
    return result


# ─────────────────────────────────────────────────────────────────────────────
# MEDIUM FIX: download_youtube_wav — return the actual written path.
# The original always returned the hardcoded global "output.wav", ignoring
# whatever filename yt-dlp actually wrote to.
# ─────────────────────────────────────────────────────────────────────────────
def download_youtube_wav(youtube_url: str) -> str:
    """Download YouTube audio as WAV and return the path yt-dlp wrote to."""
    output_path = get_output_path()
    # yt-dlp appends ".wav" via the postprocessor, so strip the extension first
    base = os.path.splitext(output_path)[0]

    cookies_file = os.getenv("COOKIES_FILE", "cookies.txt")
    ydl_opts: dict = {
        "format": "bestaudio/best",
        "outtmpl": base,
        "quiet": True,
        "noplaylist": True,
        "postprocessors": [{
            "key": "FFmpegExtractAudio",
            "preferredcodec": "wav",
            "preferredquality": "192",
        }],
    }
    # HIGH FIX #6 (partial): only pass cookiefile if the file actually exists,
    # avoiding silent errors when cookies.txt is absent or gitignored.
    if os.path.isfile(cookies_file):
        ydl_opts["cookiefile"] = cookies_file

    with yt_dlp.YoutubeDL(ydl_opts) as ydl:
        ydl.download([youtube_url])

    # Return the real path yt-dlp wrote
    return base + ".wav"


# ─────────────────────────────────────────────────────────────────────────────
# MEDIUM FIX: FAISS persistence — skip re-embedding if index already exists.
# The original rebuilt the index from scratch on every new Streamlit session,
# re-calling OpenAI Embeddings for every chunk of the transcript.
# ─────────────────────────────────────────────────────────────────────────────
def _faiss_cache_dir(video_url: str) -> str:
    url_hash = hashlib.md5(video_url.encode()).hexdigest()
    cache_root = os.path.join(tempfile.gettempdir(), "transcript_faiss_cache")
    os.makedirs(cache_root, exist_ok=True)
    return os.path.join(cache_root, url_hash)


def get_or_build_vector_store(text: str, video_url: str) -> FAISS:
    """
    Load a persisted FAISS index for this video URL if one exists, otherwise
    build it, persist it, and return it.
    """
    embeddings = OpenAIEmbeddings()
    cache_dir = _faiss_cache_dir(video_url)

    if os.path.isdir(cache_dir):
        try:
            return FAISS.load_local(
                cache_dir, embeddings, allow_dangerous_deserialization=True
            )
        except Exception:
            pass  # Cache corrupt or incompatible — fall through and rebuild

    docs = [Document(page_content=text)]
    splitter = RecursiveCharacterTextSplitter(chunk_size=1000, chunk_overlap=50)
    final_docs = splitter.split_documents(docs)
    vector_store = FAISS.from_documents(final_docs, embeddings)
    vector_store.save_local(cache_dir)
    return vector_store


