                )
            overall_conf = compute_overall_confidence(st.session_state.result)
            st.info(f"Confidence: {overall_conf:.2f} → {label_confidence(overall_conf)}")
        else:
            st.warning("No transcript available. Please generate one first.")

    # ── Translation Tab ───────────────────────────────────────────────────────
    with tab3:
        st.markdown("### 🌍 Google Translator (Optional)")
