                transcript_path = get_transcript_path()
                with st.spinner("Translating with Google..."):
                    translate_to_english(
                        transcript_path, st.session_state.result, source_lang="auto"
                    )
            except Exception as e:
                st.error(f"Translation failed: {e}")
        else:
            st.warning("Generate a transcript first.")

    # ── Q&A Tab ───────────────────────────────────────────────────────────────
    with tab4:
        st.markdown("### 💬 Ask Questions")
        if "english_translated_text" in st.session_state:
            llm = ChatGroq(
                groq_api_key=groq_api_key,
                model_name="llama-3.3-70b-versatile",
                temperature=0.0,
                max_tokens=1024,
            )
            prompt = ChatPromptTemplate.from_template(
                """
                Answer the question using only the context provided.
                Give the most accurate response possible.

                <context>
                {context}
                </context>

                Question: {input}
                """
            )

            # MEDIUM FIX: load from persistent FAISS cache — avoid re-embedding
            video_url = st.session_state.get("m3u8_url", "unknown_video")
            if "vectors" not in st.session_state:
                with st.spinner("Building search index (cached after first run)..."):
